  test("variables_collision_in_immediately_invoked_func".fail) {
    assertCompresses(
      input = """(function(callback) {
            callback();
        })(function() {
            window.used = function() {
                var A = window.foo,
                    B = window.bar,
                    C = window.foobar;

                return (function(A, c) {
                    if (-1 === c) return A;
                    return $$(A, c);
                })(B, C);
            }.call(this);
        })""".stripMargin.trim,
      expected = """!function () {
            window.used = function () {
                return (
                    window.foo,
                    function (A, c) {
                        return -1 === c
                            ? A
                            : $$(A,c)
                    }(window.bar, window.foobar)
                );
            }.call(this);
        }()""".stripMargin.trim,
      options = AllOff
    )
  }

