            if (typeof superClass !== "function") {
                throw new TypeError();
            }
            Object.create(superClass);
        }

        function withStyles() {
            var a = EXTERNAL();
            return function(_a){
                _inherits(_a);
                function d() {}
            }(a);
        }""".stripMargin.trim,
      expected = """function _inherits(superClass) {
            if ("function" != typeof superClass)
